import{c as i,Q as t,j as s,m as l}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"编码格式:H.264 / H.265 / VP9 / AV1 / AAC / Opus","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/05-编码格式-H264-H265-VP9-AV1-AAC-Opus.md","filePath":"mediaTechLearning/05-编码格式-H264-H265-VP9-AV1-AAC-Opus.md","lastUpdated":1780887690000}'),e={name:"mediaTechLearning/05-编码格式-H264-H265-VP9-AV1-AAC-Opus.md"};function h(p,a,r,n,d,o){return t(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="编码格式-h-264-h-265-vp9-av1-aac-opus" tabindex="-1">编码格式:H.264 / H.265 / VP9 / AV1 / AAC / Opus <a class="header-anchor" href="#编码格式-h-264-h-265-vp9-av1-aac-opus" aria-label="Permalink to &quot;编码格式:H.264 / H.265 / VP9 / AV1 / AAC / Opus&quot;">​</a></h1><p>编码格式决定数据怎么压缩。选错编码,不是&quot;清晰度差一点&quot;,而是播放不了、CPU 爆、延迟高、账单贵。</p><blockquote><p>一句话先记住:<strong>H.264 是兼容性基线,H.265 / VP9 / AV1 是压缩效率换复杂度,AAC 是通用音频,Opus 是实时语音王者</strong>。</p></blockquote><hr><h2 id="一、视频编码解决什么" tabindex="-1">一、视频编码解决什么 <a class="header-anchor" href="#一、视频编码解决什么" aria-label="Permalink to &quot;一、视频编码解决什么&quot;">​</a></h2><p>视频编码器靠三类信息压缩:</p><table tabindex="0"><thead><tr><th>类型</th><th>思路</th></tr></thead><tbody><tr><td>空间冗余</td><td>一帧内部相邻像素相似</td></tr><tr><td>时间冗余</td><td>相邻帧大部分区域没变</td></tr><tr><td>感知冗余</td><td>人眼对某些细节不敏感</td></tr></tbody></table><p>所以编码器不是简单压缩,它会运动估计、预测、变换、量化、熵编码。代价是 CPU / GPU 计算。</p><hr><h2 id="二、h-264-默认安全选项" tabindex="-1">二、H.264:默认安全选项 <a class="header-anchor" href="#二、h-264-默认安全选项" aria-label="Permalink to &quot;二、H.264:默认安全选项&quot;">​</a></h2><p>优点:</p><ul><li>浏览器、手机、电视、硬件解码支持最广</li><li>编码器成熟</li><li>工具链稳定</li></ul><p>常用:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mov</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> libx264</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -crf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 23</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -preset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> medium</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>生产里,如果你不知道目标端是什么,先用 H.264 + AAC。</p><hr><h2 id="三、h-265-更省码率-但兼容要查" tabindex="-1">三、H.265:更省码率,但兼容要查 <a class="header-anchor" href="#三、h-265-更省码率-但兼容要查" aria-label="Permalink to &quot;三、H.265:更省码率,但兼容要查&quot;">​</a></h2><p>H.265 / HEVC 通常比 H.264 更省码率,尤其 4K 场景明显。但问题是:</p><ul><li>浏览器支持不统一</li><li>专利授权复杂</li><li>老设备硬解不一定有</li></ul><p>适合:</p><ul><li>App 内播放且设备可控</li><li>4K 点播</li><li>私有分发</li></ul><p>不适合:</p><ul><li>面向所有浏览器的默认格式</li></ul><hr><h2 id="四、vp9-av1-开放生态和更高压缩" tabindex="-1">四、VP9 / AV1:开放生态和更高压缩 <a class="header-anchor" href="#四、vp9-av1-开放生态和更高压缩" aria-label="Permalink to &quot;四、VP9 / AV1:开放生态和更高压缩&quot;">​</a></h2><p>VP9 常见于 WebM,AV1 是更新一代。AV1 压缩效率好,但编码慢,硬件支持还要看设备代际。</p><p>适合:</p><ul><li>大规模点播平台</li><li>有转码集群</li><li>目标设备支持明确</li></ul><p>不适合:</p><ul><li>小团队一上来全量转 AV1</li><li>实时低延迟场景里用超慢参数</li></ul><hr><h2 id="五、aac-通用音频基线" tabindex="-1">五、AAC:通用音频基线 <a class="header-anchor" href="#五、aac-通用音频基线" aria-label="Permalink to &quot;五、AAC:通用音频基线&quot;">​</a></h2><p>AAC 是 MP4 / HLS / 移动端里最常见的音频选择:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.wav</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b:a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 128k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.m4a</span></span></code></pre></div><p>音乐、点播、普通视频都稳。WebRTC 不靠 AAC 做实时语音主力。</p><hr><h2 id="六、opus-实时语音优先" tabindex="-1">六、Opus:实时语音优先 <a class="header-anchor" href="#六、opus-实时语音优先" aria-label="Permalink to &quot;六、Opus:实时语音优先&quot;">​</a></h2><p>Opus 是 WebRTC 音频核心。强项:</p><ul><li>低延迟</li><li>低码率语音质量好</li><li>支持可变码率</li><li>弱网抗性好</li></ul><p>语音会议优先保 Opus 音频。视频可以降分辨率、降帧率,音频断了会议直接不可用。</p><hr><h2 id="七、硬编码和软编码" tabindex="-1">七、硬编码和软编码 <a class="header-anchor" href="#七、硬编码和软编码" aria-label="Permalink to &quot;七、硬编码和软编码&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>软编码</td><td>参数灵活,质量可控</td><td>吃 CPU</td></tr><tr><td>硬编码</td><td>快,省电</td><td>质量和参数受硬件限制</td></tr></tbody></table><p>移动端、直播推流、实时会议常依赖硬编码。点播离线转码更常用软编码或专用转码集群。</p><hr><h2 id="八、踩坑提醒" tabindex="-1">八、踩坑提醒 <a class="header-anchor" href="#八、踩坑提醒" aria-label="Permalink to &quot;八、踩坑提醒&quot;">​</a></h2><ol><li><strong>只看压缩率不看兼容性</strong>——AV1 再省,播不了就是 0。</li><li><strong>H.265 不等于 Web 默认可用</strong>。</li><li><strong>实时场景别用离线慢参数</strong>。</li><li><strong>会议先保 Opus 音频</strong>。</li><li><strong>硬编码输出质量要实测</strong>——不同设备差距很大。</li></ol><p>下一篇:<code>06-GOP、I/P/B 帧、关键帧.md</code>。</p>',48)])])}const c=i(e,[["render",h]]);export{u as __pageData,c as default};
